          preferredLanguages: parameters.preferredLanguages,
          propertyPatterns: [],
          schema: NonClassStruct.schema.properties.$identifier.type,
          valueVariable: parameters.focusIdentifier,
          variablePrefix: parameters.variablePrefix,
