  export function sparqlConstructQuery({
    filter,
    ignoreRdfType,
    preferredLanguages,
    prefixes,
    subject,
    ...queryParameters
  }: {
    filter?: NumericsStruct.Filter;
    ignoreRdfType?: boolean;
    prefixes?: { [prefix: string]: string };
    preferredLanguages?: readonly string[];
    subject: NamedNode | Variable;
  } & Omit<
    sparqljs.ConstructQuery,
    "prefixes" | "queryType" | "type"
  >): sparqljs.ConstructQuery {
    const variablePrefix =
      subject.termType === "Variable" ? subject.value : "numericsStruct";

    return {
      ...queryParameters,
      prefixes: prefixes ?? {},
      queryType: "CONSTRUCT",
      template: (queryParameters.template ?? []).concat(
        NumericsStruct.focusSparqlConstructTriples({
          filter,
          focusIdentifier: subject,
          ignoreRdfType: !!ignoreRdfType,
          variablePrefix,
        }),
      ),
      type: "query",
      where: (queryParameters.where ?? []).concat(
        $normalizeSparqlWherePatterns(
          NumericsStruct.focusSparqlWherePatterns({
            filter,
            focusIdentifier: subject,
            ignoreRdfType: !!ignoreRdfType,
            preferredLanguages,
            variablePrefix,
          }),
        ),
      ),
    };
  }

